package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testLookAheadReturnsNextChar() throws IOException {
        // Arrange
        extendedBufferedReader = spy(extendedBufferedReader);
        doNothing().when(extendedBufferedReader).mark(1);
        doReturn((int) 'a').when(extendedBufferedReader).read();
        doNothing().when(extendedBufferedReader).reset();

        // Act
        int result = extendedBufferedReader.lookAhead();

        // Assert
        assertEquals('a', result);
        verify(extendedBufferedReader).mark(1);
        verify(extendedBufferedReader).read();
        verify(extendedBufferedReader).reset();
    }

    @Test
    void testLookAheadReturnsEndOfStream() throws IOException {
        // Arrange
        extendedBufferedReader = spy(extendedBufferedReader);
        doNothing().when(extendedBufferedReader).mark(1);
        doReturn(ExtendedBufferedReader.END_OF_STREAM).when(extendedBufferedReader).read();
        doNothing().when(extendedBufferedReader).reset();

        // Act
        int result = extendedBufferedReader.lookAhead();

        // Assert
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        verify(extendedBufferedReader).mark(1);
        verify(extendedBufferedReader).read();
        verify(extendedBufferedReader).reset();
    }

    @Test
    void testLookAheadThrowsIOException() throws IOException {
        // Arrange
        extendedBufferedReader = spy(extendedBufferedReader);
        doThrow(new IOException("mark failed")).when(extendedBufferedReader).mark(1);

        // Act & Assert
        try {
            extendedBufferedReader.lookAhead();
        } catch (IOException e) {
            assertEquals("mark failed", e.getMessage());
        }
    }
}
